817→export const getFollowingFeedService = async(limit, userId, before) => {
818→    if (!userId) {
819→        throw { status: 401, error: 'authentication required' };
820→    }
821→    if (isNaN(limit) || limit > 20 || limit < 1) {
822→        throw { status: 400, error: 'limit should be integer, not below 1 and higher than 20' };
823→    }
824→
825→    const parsedLimit = parseInt(limit);
826→
827→    // Step 1: Get IDs of users this person follows (lightweight — just UUIDs)
828→    const { data: followingRows, error: followError } = await supabase
829→        .from('follows')
830→        .select('following_id')
831→        .eq('follower_id', userId);
832→
833→    if (followError) {
834→        console.error('supabase error fetching following list:', followError.message);
835→        throw { status: 500, error: 'supabase error fetching following list' };
836→    }
837→
838→    const followingIds = followingRows.map(r => r.following_id);
839→
840→    // If user follows nobody, return empty immediately (zero egress)
841→    if (followingIds.length === 0) {
842→        return { data: [], hasMore: false };
843→    }
844→
845→    // Step 2: Fetch journals from followed users (reuse existing SELECT pattern)
846→    let query = supabase
847→        .from('journals')
848→        .select(JOURNAL_WITH_COUNTS_SELECT)
849→        .eq('privacy', 'public')
850→        .in('user_id', followingIds)
851→        .order('created_at', { ascending: false })
852→        .order('id', { ascending: false })
853→        .limit(parsedLimit + 1);
854→
855→    if (before) {
856→        query = query.lt('created_at', before);
857→    }
858→
859→    const { data, error } = await query;
860→
861→    if (error) {
862→        console.error('supabase error fetching following feed:', error.message);
863→        throw { status: 500, error: 'supabase error fetching following feed' };
864→    }
865→
866→    if (data.length === 0) {
867→        return { data: [], hasMore: false };
868→    }
869→
870→    // Step 3: Personalization (same pattern as getJournalsService)
871→    const journalIds = data.map(j => j.id);
872→    const [userLikes, userBookmarks, userReactions] = await Promise.all([
873→        supabase.from('likes').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
874→        supabase.from('bookmarks').select('journal_id').in('journal_id', journalIds).eq('user_id', userId),
875→        supabase.from('reactions').select('journal_id, reaction_type').in('journal_id', journalIds).eq('user_id', userId)
876→    ]);
877→
878→    const userHasLikedSet = new Set(userLikes.data?.map(j => j.journal_id) || []);
879→    const userHasBookmarkedSet = new Set(userBookmarks.data?.map(j => j.journal_id) || []);
880→    const userReactionMap = new Map((userReactions.data || []).map(r => [r.journal_id, r.reaction_type]));
881→
882→    await attachRepostSources(data);
883→
884→    const formattedData = data.map(journal => ({
885→        ...journal,
886→        has_liked: userHasLikedSet.has(journal.id),
887→        has_bookmarked: userHasBookmarkedSet.has(journal.id),
888→        user_reaction: userReactionMap.get(journal.id) || null
889→    }));
890→
891→    const hasMore = data.length > parsedLimit;
892→    const slicedData = hasMore ? formattedData.slice(0, parsedLimit) : formattedData;
893→
894→    return { data: slicedData, hasMore };
895→}
